import jsonfrom pathlib import Pathfrom typing import Dict, Anyfrom invoice_agent.schemas import InvoiceDatadef send_notification(invoice_data: Dict[str, Any]) -> str:    """    Generate human-readable summary and structured JSON output    for Customer Service.    """    # Validate input against schema    invoice = InvoiceData(**invoice_data)    # Create output directory if it doesn't exist    output_dir = Path("output")    output_dir.mkdir(exist_ok=True)    # Write structured JSON    json_path = output_dir / "outbound_email.json"    with open(json_path, "w", encoding="utf-8") as f:        json.dump(invoice.model_dump(), f, indent=2)    # Create human-readable summary    summary_text = _build_summary(invoice)    text_path = output_dir / "outbound_email.txt"    with open(text_path, "w", encoding="utf-8") as f:        f.write(summary_text)    return f"Notification generated successfully: {json_path} and {text_path}"def _build_summary(invoice: InvoiceData) -> str:    """    Build human-readable summary for Customer Service.    """    lines = []    lines.append("INVOICE INTAKE SUMMARY")    lines.append("=" * 40)    lines.append("")    lines.append(f"Vendor: {invoice.vendor_name}")    lines.append(f"Invoice Number: {invoice.invoice_number}")    lines.append(f"Invoice Date: {invoice.invoice_date}")    lines.append(f"Due Date: {invoice.due_date}")    lines.append(f"Payment Terms: {invoice.payment_terms}")    lines.append(f"Currency: {invoice.currency}")    lines.append(f"Customer PO: {invoice.customer_po_number}")    lines.append("")    lines.append("FINANCIAL SUMMARY")    lines.append("-" * 40)    lines.append(f"Subtotal: {invoice.subtotal}")    lines.append(f"Taxes: {invoice.taxes}")    lines.append(f"Total Due: {invoice.total_due}")    lines.append("")    lines.append("SHIP-TO LOCATIONS")    lines.append("-" * 40)    for site in invoice.ship_to_locations:        lines.append(f"Site Name: {site.site_name}")        lines.append(f"Address: {site.address}")        lines.append(f"Receiving Hours: {site.receiving_hours}")        lines.append(f"Delivery Window: {site.delivery_window}")        lines.append("")    lines.append("LINE ITEMS")    lines.append("-" * 40)    for item in invoice.line_items:        lines.append(            f"SKU: {item.sku} | Desc: {item.description} | "            f"Qty: {item.quantity} | Unit: {item.unit_price} | "            f"Line Total: {item.line_total}"        )    lines.append("")    lines.append("NOTES")    lines.append("-" * 40)    lines.append(str(invoice.notes))    return "\n".join(lines)